(
  (
    NOT(
      (
        (CAST(AREA_ITACA AS STRING) IN ('AR051', 'AR056'))
        AND (
              (NOT(CAST((SUBSTRING(CODIGO_ITACA, 1, 4)) AS STRING) IN ('A100', 'A102', 'P060', 'P062')))
              OR ((SUBSTRING(CODIGO_ITACA, 1, 4)) IS NULL)
            )
      )
      AND (
            (
              NOT(
                CAST(CODIGO_ITACA AS STRING) IN ('G50191', 'I0191', 'G0191', 'I50191', 'P0419', 'G0131', 'I50031', 'R0511'))
            )
            OR (CODIGO_ITACA IS NULL)
          ))
  )
  OR (
       (
         (
           (CAST(AREA_ITACA AS STRING) IN ('AR051', 'AR056'))
           AND (
                 (NOT(CAST((SUBSTRING(CODIGO_ITACA, 1, 4)) AS STRING) IN ('A100', 'A102', 'P060', 'P062')))
                 OR ((SUBSTRING(CODIGO_ITACA, 1, 4)) IS NULL)
               )
         )
         AND (
               (
                 NOT(
                   CAST(CODIGO_ITACA AS STRING) IN ('G50191', 'I0191', 'G0191', 'I50191', 'P0419', 'G0131', 'I50031', 'R0511'))
               )
               OR (CODIGO_ITACA IS NULL)
